def time_ago(pub_str):
    try:
        pub_dt = datetime.strptime(pub_str.strip()[:10], "%Y-%m-%d")
    except:
        pub_dt = datetime.now()
    diff_h = int((datetime.now() - pub_dt).total_seconds() / 3600)
    if diff_h <= 0:   return "Just now"
    if diff_h < 24:   return f"{diff_h}h ago"
    return f"{diff_h//24}d ago"

def detect_local(airlines_str):
    for a in LOCAL_AIRLINES:
        if a.lower() in airlines_str.lower():
            return a
    return None

def generate_mock():
    titles = [
        "Riyadh Air updates its fleet delivery schedule for upcoming operations",
        "Saudia expands capacity to meet high passenger demand this season",
        "Flynas announces new direct routes connecting Jeddah to international hubs",
        "Flyadeal enhances ground handling turnaround times at King Abdulaziz Airport",
        "Emirates increases daily frequencies to key GCC destinations",
        "Qatar Airways optimises airspace routing to improve fuel efficiency",
        "Gulf Air reports significant growth in corporate travel segment",
        "Wizz Air expands low-cost network across Saudi peripheral airports",
        "Air Cairo adds fleet capacity for regional leisure routes",
        "The Helicopter Company expands medical evacuation infrastructure in KSA",
        "Turkish Airlines adds new codeshare agreement on Saudi routes",
        "Oman Air boosts Muscat-Riyadh capacity ahead of peak season",
    ]
    summaries = [
        "Strategic fleet optimisation aimed at enhancing block-hour efficiency and maintaining strict network schedule integrity.",
        "Ground handling operations scale up workforce deployment to manage baggage throughput and optimise airport terminal dwell times.",
        "Aviation authorities approve slot allocations for upcoming winter schedule expansion across regional airports.",
        "Operations management implements revised aircraft maintenance turnarounds to maximise asset utilisation.",
        "Fuel hedging strategies and network rerouting minimise the impact of regional airspace slot constraints.",
    ]
    rows = []
    for i in range(18):
        t = random.choice(titles) + f" (Report #{i+200})"
        s = random.choice(summaries)
        full = f"{t} {s}"
        airlines = [a for a in AIRLINES_LIST if a.lower() in full.lower()]
        is_ksa = any(k.lower() in full.lower() for k in KSA_KEYWORDS)
        is_me  = any(k.lower() in full.lower() for k in ME_KEYWORDS)
        ops_w  = ["delay","strike","maintenance","airport","fuel","airspace","route",
                  "slots","handling","capacity","turnaround"]
        cat = "Operations / Infrastructure" if any(w in full.lower() for w in ops_w) else "Commercial / Fleet"
        hrs_back = random.randint(0, 96)
        sim_dt = datetime.now() - timedelta(hours=hrs_back)
        al_str = ", ".join(airlines) if airlines else "Riyadh Air"
        rows.append({
            "Title": t, "Summary": s,
            "Link": "https://simpleflying.com",
            "Published": sim_dt.strftime("%Y-%m-%d"),
            "PublishedDT": sim_dt,
            "Airlines": al_str,
            "Region": "Saudi Arabia 🇸🇦" if is_ksa else ("Middle East 🌍" if is_me else "Global / Regional"),
            "Type": cat,
            "IsLocal": any(la.lower() in al_str.lower() for la in LOCAL_AIRLINES),
        })
    return pd.DataFrame(rows)

@st.cache_data(ttl=900)
def fetch_news():
    urls = ["https://simpleflying.com/feed/","https://www.flightglobal.com/135.rss"]
    articles = []
    for url in urls:
        try:
            import feedparser as fp
            feed = fp.parse(url)
            for e in feed.entries:
                title   = e.title
                summary = e.summary if "summary" in e else ""
                link    = e.link
                pub_dt  = datetime(*e.published_parsed[:6]) if "published_parsed" in e else datetime.now()
                full    = f"{title} {summary}"
                airlines = [a for a in AIRLINES_LIST if a.lower() in full.lower()]
                is_ksa  = any(k.lower() in full.lower() for k in KSA_KEYWORDS)
                is_me   = any(k.lower() in full.lower() for k in ME_KEYWORDS)
                ops_w   = ["delay","strike","maintenance","airport","fuel","airspace",
                           "route","slots","handling","capacity","turnaround"]
                cat = "Operations / Infrastructure" if any(w in full.lower() for w in ops_w) else "Commercial / Fleet"
                al_str = ", ".join(airlines) if airlines else "Market Intelligence"
                if airlines or is_ksa or is_me:
                    articles.append({
                        "Title": title, "Summary": summary, "Link": link,
                        "Published": pub_dt.strftime("%Y-%m-%d"), "PublishedDT": pub_dt,
                        "Airlines": al_str,
                        "Region": "Saudi Arabia 🇸🇦" if is_ksa else ("Middle East 🌍" if is_me else "Global / Regional"),
                        "Type": cat,
                        "IsLocal": any(la.lower() in al_str.lower() for la in LOCAL_AIRLINES),
                    })
        except: continue
    df = pd.DataFrame(articles)
    mock = generate_mock()
    return mock if df.empty else pd.concat([df, mock], ignore_index=True)

