df_f = df[(df["Region"].isin(sel_region)) & (df["Type"].isin(sel_type))]
df_local = df_f[df_f["IsLocal"]==True]
df_intl  = df_f[df_f["IsLocal"]==False]

def render_card(row):
    carrier = detect_local(row["Airlines"])
    meta    = AIRLINE_META.get(carrier, {})
    cls     = meta.get("cls","")
    logo    = meta.get("logo","")

    al_str = row["Airlines"]
    if len(al_str) > 42: al_str = al_str[:42]+"…"

    region_cls = "tag-ksa" if "Saudi" in row["Region"] else                  ("tag-me" if "Middle" in row["Region"] else "tag-glob")
    type_cls = "tag-ops" if "Operations" in row["Type"] else "tag-comm"

    try:
        pub_dt = row.get("PublishedDT")
        if pub_dt is None or (isinstance(pub_dt, float)):
            pub_dt = datetime.strptime(row["Published"], "%Y-%m-%d")
        diff_h = int((datetime.now() - pub_dt).total_seconds() / 3600)
        t_str  = "Just now" if diff_h<=0 else (f"{diff_h}h ago" if diff_h<24 else f"{diff_h//24}d ago")
    except:
        t_str = row["Published"]

    summary_s = row["Summary"][:210] + ("…" if len(row["Summary"])>210 else "")
    logo_html = f'''<div class="card-logo-wrap"><img src="{logo}" alt="logo"></div>''' if logo else ""

    # Entire card is a link — click anywhere opens article
    st.markdown(f"""
    <a class="news-card {cls}" href="{row["Link"]}" target="_blank" rel="noopener noreferrer">
      {logo_html}
      <div class="news-card-title">{row["Title"]}</div>
      <div class="news-card-summary">{summary_s}</div>
      <div class="news-card-meta">
        <span class="tag {region_cls}">{row["Region"]}</span>
        <span class="tag {type_cls}">{row["Type"]}</span>
        <span class="tag tag-air">✈ {al_str}</span>
        <span class="tag tag-time">🕐 {t_str}</span>
      </div>
    </a>
    """, unsafe_allow_html=True)

# ════════════════════════════════════════════
